 if (!el) return;
 const LAT = 11.6814, LON = 75.6478;
 const url = `https://api.open-meteo.com/v1/forecast?latitude=${LAT}&longitude=${LON}&current=temperature_2m,weathercode,windspeed_10m,relative_humidity_2m&timezone=Asia%2FKolkata`;
 const WMO = {
 0:'вҳҖпёҸ Clear', 1:'рҹҢӨ Mostly Clear', 2:'вӣ… Partly Cloudy', 3:'вҳҒпёҸ Overcast',
 45:'рҹҢ« Foggy', 51:'рҹҢҰ Light Drizzle', 61:'рҹҢ§ Light Rain',
 63:'рҹҢ§ Moderate Rain', 65:'рҹҢ§ Heavy Rain', 80:'рҹҢҰ Showers', 95:'вӣҲ Thunderstorm',
 };
 fetch(url)
