(function initShareBtn() {
 const btns = document.querySelectorAll('.share-btn');
 btns.forEach(btn => {
 if (!navigator.share) { btn.style.display = 'none'; return; }
 btn.addEventListener('click', () => {
 navigator.share({
 title: 'Kakkamvelly Sreekrishna Temple',
 text: 'аҙ№аҙ°аөҮ аҙ•аөғаҙ·аөҚаҙЈ рҹҷҸ Visit Kakkamvelly Sreekrishna Temple, Kozhikode, Kerala',
 url: window.location.href,
 }).catch(() => {});
 });
 });
})();
(function() {
 const form = document.getElementById('contact-form');
 if (!form) return;
 function showError(id, show) {
 const el = document.getElementById(id);
 if (el) el.classList.toggle('visible', show);
 }
 function validate() {
 let ok = true;
 const name = form.querySelector('[name="name"]');
 const email = form.querySelector('[name="email"]');
 const msg = form.querySelector('[name="message"]');
 if (name) {
 const v = name.value.trim().length >= 2;
 showError('name-error', !v);
 if (!v) ok = false;
 }
 if (email) {
 const v = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.value.trim());
 showError('email-error', !v);
 if (!v) ok = false;
 }
 if (msg) {
 const v = msg.value.trim().length >= 5;
 showError('message-error', !v);
 if (!v) ok = false;
 }
 return ok;
 }
 form.addEventListener('submit', async function(e) {
 e.preventDefault();
 if (!validate()) return;
 const btn = document.getElementById('contact-submit');
 const origHTML = btn ? btn.innerHTML : '';
 if (btn) { btn.innerHTML = 'вҸі аҙ…аҙҜаҙ•аөҚаҙ•аөҒаҙЁаөҚаҙЁаөҒ...'; btn.disabled = true; }
 const banner = document.getElementById('form-success-banner');
 try {
 const res = await fetch(form.action || 'https://formspree.io/f/kakkamvellytemple',
 { method: 'POST', body: new FormData(form), headers: { 'Accept': 'application/json' } });
 if (res.ok) {
 form.reset();
 form.querySelectorAll('.field-error-msg').forEach(el => el.classList.remove('visible'));
 if (banner) { banner.classList.add('visible'); setTimeout(() => banner.classList.remove('visible'), 8000); }
 } else throw new Error();
 } catch {
 alert('аҙҰаҙҜаҙөаҙҫаҙҜаҙҝ аҙ¬аҙЁаөҚаҙ§аҙӘаөҚаҙӘаөҶаҙҹаөҒаҙ•: kakkamvellytemple@gmail.com');
 }
 if (btn) { btn.innerHTML = origHTML; btn.disabled = false; }
 });
 form.querySelectorAll('input, textarea').forEach(el => {
 el.addEventListener('blur', validate);
 });
})();
(function() {
'use strict';
var TRANSLATIONS = {
 ml: {
 nav_home: 'аҙ®аөҒаҙ–аөҚаҙҜ',
 nav_about: 'аҙ•аөҚаҙ·аөҮаҙӨаөҚаҙ°аҙӮ',
 nav_timings: 'аҙёаҙ®аҙҜаҙӮ',
 nav_gallery: 'аҙ—аөҚаҙҜаҙҫаҙІаҙұаҙҝ',
 nav_location: 'аҙёаөҚаҙҘаҙІаҙӮ',
 nav_kulam: 'аҙ•аөҒаҙіаҙӮ',
 hero_tagline: 'аҙ№аҙ°аөҮ аҙ•аөғаҙ·аөҚаҙЈ',
 hero_title: 'аҙ•аҙ•аөҚаҙ•аҙӮаҙөаөҶаҙіаөҚаҙіаҙҝ\nаҙ¶аөҚаҙ°аөҖаҙ•аөғаҙ·аөҚаҙЈ аҙ•аөҚаҙ·аөҮаҙӨаөҚаҙ°аҙӮ',
 hero_subtitle:'Kakkamvelly Sreekrishna Temple',
 hero_btn1: 'аҙөаҙҙаҙҝ аҙ•аҙҫаҙЈаҙҝаҙ•аөҚаҙ•аөҒаҙ•',
 hero_btn2: 'аҙ•аөҚаҙ·аөҮаҙӨаөҚаҙ° аҙёаҙ®аҙҜаҙӮ',
 },
 en: {
 nav_home: 'Home',
 nav_about: 'Temple',
 nav_timings: 'Timings',
 nav_gallery: 'Gallery',
 nav_location: 'Location',
 nav_kulam: 'Kulam',
 hero_tagline: 'HARE KRISHNA',
 hero_title: 'Kakkamvelly\nSreekrishna Temple',
 hero_subtitle:'аҙ•аҙ•аөҚаҙ•аҙӮаҙөаөҶаҙіаөҚаҙіаҙҝ аҙ¶аөҚаҙ°аөҖаҙ•аөғаҙ·аөҚаҙЈ аҙ•аөҚаҙ·аөҮаҙӨаөҚаҙ°аҙӮ',
 hero_btn1: 'Get Directions',
 hero_btn2: 'Temple Timings',
 }
};
var NAV_MAP = [
 { sel: '.nav-link[href="#home"]', key: 'nav_home' },
 { sel: '.nav-link[href="#about"]', key: 'nav_about' },
 { sel: '.nav-link[href="#timings"]', key: 'nav_timings' },
 { sel: '.nav-link[href="#gallery"]', key: 'nav_gallery' },
 { sel: '.nav-link[href="#location"]', key: 'nav_location' },
 { sel: '.nav-link[href="#kulam"]', key: 'nav_kulam' },
];
var currentLang = localStorage.getItem('kvt-lang') || 'ml';
function applyLang(lang) {
 if (!TRANSLATIONS[lang]) return;
 currentLang = lang;
 localStorage.setItem('kvt-lang', lang);
 var T = TRANSLATIONS[lang];
 NAV_MAP.forEach(function(item) {
 document.querySelectorAll(item.sel).forEach(function(el) {
 if (T[item.key]) el.textContent = T[item.key];
 });
 });
 var heroTitle = document.querySelector('.hero-title');
 if (heroTitle && T.hero_title) {
 heroTitle.innerHTML = T.hero_title.replace('\n', '<br/>');
 }
 var heroTagline = document.querySelector('.hero-tagline');
 if (heroTagline && T.hero_tagline) heroTagline.textContent = T.hero_tagline;
 var heroSubtitle = document.querySelector('.hero-subtitle');
 if (heroSubtitle && T.hero_subtitle) heroSubtitle.textContent = T.hero_subtitle;
 var heroBtns = document.querySelectorAll('.hero-actions .btn');
 if (heroBtns[0] && T.hero_btn1)
 heroBtns[0].innerHTML = '<i class="fa-solid fa-map-location-dot" aria-hidden="true"></i> ' + T.hero_btn1;
 if (heroBtns[1] && T.hero_btn2)
 heroBtns[1].innerHTML = '<i class="fa-regular fa-clock" aria-hidden="true"></i> ' + T.hero_btn2;
 var attrKey = 'data-' + lang;
 document.querySelectorAll('[data-ml][data-en]').forEach(function(el) {
 var val = el.getAttribute(attrKey);
 if (val) el.textContent = val;
 });
 document.querySelectorAll('.nlp-btn, .nav-lang-btn, .lang-btn').forEach(function(b) {
 b.classList.toggle('active', b.dataset.lang === lang);
 });
 document.body.classList.toggle('lang-en', lang === 'en');
 document.documentElement.lang = lang === 'ml' ? 'ml' : 'en';
}
function initLangButtons() {
 document.querySelectorAll('.nlp-btn, .nav-lang-btn').forEach(function(btn) {
 btn.addEventListener('click', function(e) {
 e.stopPropagation();
 applyLang(btn.dataset.lang);
 });
 });
 applyLang(currentLang);
}
if (document.readyState === 'loading') {
 document.addEventListener('DOMContentLoaded', initLangButtons);
} else {
 initLangButtons();
}
setTimeout(function() { applyLang(currentLang); }, 600);
setTimeout(function() { applyLang(currentLang); }, 2000);
})();
